function checkLock() {
  const hasPackageJson = exists(packageJsonPath);
  const hasPackageLock = exists(packageLockPath);

  section('package-lock.json Check');

  if (!hasPackageJson) {
    print('ERROR: package.json not found in current directory.');
    process.exitCode = 1;
    return;
  }

  if (!hasPackageLock) {
    print('WARNING: package-lock.json not found.');
    print('Generate it with: npm install');
    process.exitCode = 1;
    return;
  }

  print('OK: package.json and package-lock.json are present.');

  try {
    const lock = readJson(packageLockPath);
    if (lock.lockfileVersion == null) {
      print('WARNING: lock file exists but lockfileVersion is missing.');
      process.exitCode = 1;
      return;
    }
    print(`Detected lockfileVersion: ${lock.lockfileVersion}`);
  } catch (err) {
    print(`ERROR: unable to parse package-lock.json: ${err.message}`);
    process.exitCode = 1;
  }
}

function printCommands() {
  section('Command Reference');
  for (const group of getCommands()) {
    print(group.title);
    for (const command of group.commands) {
      print(`  ${command}`);
    }
    print();
  }
}

function main() {
  const args = new Set(process.argv.slice(2));

  if (args.has('--check-lock')) {
    checkLock();
    return;
  }

  if (args.has('--print-commands')) {
    printCommands();
    return;
  }

  const docs = buildDocs();

  if (args.has('--write-docs')) {
    fs.writeFileSync(docsPath, docs, 'utf8');
    print(`Wrote ${docsPath}`);
    return;
  }

  print(docs);
}

